import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Navbar from '../../home/components/Navbar';
import FileParsingStep from './components/FileParsingStep';
import HeaderHandlingStep from './components/HeaderHandlingStep';
import FieldMappingStep from './components/FieldMappingStep';
import DataValidationStep from './components/DataValidationStep';
import DataCorrectionStep from './components/DataCorrectionStep';
import IngestionConfirmationStep from './components/IngestionConfirmationStep';

type StepStatus = 'pending' | 'processing' | 'completed' | 'error';

interface Step {
  id: number;
  key: string;
  name: string;
  status: StepStatus;
  description?: string;
}

const INITIAL_STEPS: Step[] = [
  { id: 1, key: 'parse', name: '文件解析', status: 'processing', description: '解析上传的文件格式' },
  { id: 2, key: 'header', name: '表头处理', status: 'pending', description: '识别和清洗表头信息' },
  { id: 3, key: 'mapping', name: '字段映射', status: 'pending', description: '建立源数据与标准字段的映射' },
  { id: 4, key: 'validation', name: '数据校验', status: 'pending', description: '根据规则校验数据有效性' },
  { id: 5, key: 'correction', name: '数据修正', status: 'pending', description: '修正校验发现的问题' },
  { id: 6, key: 'storage', name: '入库确认', status: 'pending', description: '确认数据存入数据库' },
];

export default function TaskDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [activeStepId, setActiveStepId] = useState<number>(1);
  const [steps, setSteps] = useState<Step[]>(INITIAL_STEPS);

  const activeStep = steps.find(s => s.id === activeStepId) || steps[0];

  const handleNext = () => {
    const currentIndex = steps.findIndex(s => s.id === activeStepId);
    if (currentIndex < steps.length - 1) {
      const newSteps = [...steps];
      newSteps[currentIndex].status = 'completed';
      newSteps[currentIndex + 1].status = 'processing';
      setSteps(newSteps);
      setActiveStepId(steps[currentIndex + 1].id);
    }
  };

  const handleBack = () => {
    const currentIndex = steps.findIndex(s => s.id === activeStepId);
    if (currentIndex > 0) {
      setActiveStepId(steps[currentIndex - 1].id);
    }
  };

  const handleComplete = () => {
    const newSteps = [...steps];
    newSteps[newSteps.length - 1].status = 'completed';
    setSteps(newSteps);
    // Optionally navigate away or show success message
    alert('任务入库成功！');
    navigate('/tasks');
  };

  const getStatusIcon = (status: StepStatus, index: number) => {
    switch (status) {
      case 'completed':
        return <i className="ri-checkbox-circle-fill text-teal-600 text-xl"></i>;
      case 'processing':
        return (
          <div className="w-5 h-5 rounded-full border-2 border-teal-600 border-t-transparent animate-spin"></div>
        );
      case 'error':
        return <i className="ri-close-circle-fill text-red-500 text-xl"></i>;
      default:
        return (
          <div className="w-5 h-5 rounded-full border-2 border-gray-300 flex items-center justify-center text-xs text-gray-500 font-medium">
            {index + 1}
          </div>
        );
    }
  };

  const renderStepContent = () => {
    switch (activeStep.key) {
      case 'parse':
        return <FileParsingStep onNext={handleNext} />;
      case 'header':
        return <HeaderHandlingStep onNext={handleNext} onBack={handleBack} />;
      case 'mapping':
        return <FieldMappingStep onNext={handleNext} onBack={handleBack} />;
      case 'validation':
        return <DataValidationStep onNext={handleNext} onBack={handleBack} />;
      case 'correction':
        return <DataCorrectionStep onNext={handleNext} onBack={handleBack} />;
      case 'storage':
        return <IngestionConfirmationStep onComplete={handleComplete} onBack={handleBack} />;
      default:
        return <div>Unknown Step</div>;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <Navbar />
      
      <main className="flex-grow max-w-[1600px] w-full mx-auto px-6 py-8 pt-24">
        {/* Header */}
        <div className="mb-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button 
              onClick={() => navigate('/tasks')}
              className="text-gray-500 hover:text-gray-700 flex items-center gap-1 cursor-pointer transition-colors"
            >
              <i className="ri-arrow-left-line text-xl"></i>
            </button>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">数据处理任务 – 详情</h1>
              <div className="flex items-center gap-2 text-sm text-gray-500 mt-1">
                <span>任务ID: {id || 'T-20250126-001'}</span>
                <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
                <span>创建时间: 2025-01-26 14:30</span>
              </div>
            </div>
          </div>
          <div className="flex gap-3">
            <button className="px-4 py-2 bg-white border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 text-sm font-medium shadow-sm transition-colors">
              暂停任务
            </button>
            <button className="px-4 py-2 bg-red-50 border border-red-200 text-red-600 rounded-lg hover:bg-red-100 text-sm font-medium shadow-sm transition-colors">
              取消任务
            </button>
          </div>
        </div>

        <div className="flex gap-6 h-[calc(100vh-200px)]">
          {/* Left Sidebar: Steps */}
          <div className="w-80 bg-white rounded-xl shadow-sm border border-gray-100 flex flex-col overflow-hidden">
            <div className="p-4 border-b border-gray-100 bg-gray-50/50">
              <h3 className="font-semibold text-gray-900">处理流程</h3>
            </div>
            <div className="flex-1 overflow-y-auto py-4">
              <div className="relative px-6">
                {/* Vertical Line */}
                <div className="absolute left-[39px] top-4 bottom-4 w-0.5 bg-gray-100"></div>
                
                {steps.map((step, index) => {
                  const isActive = step.id === activeStepId;
                  const isClickable = step.status !== 'pending';
                  
                  return (
                    <div 
                      key={step.id} 
                      className={`relative flex gap-4 mb-8 last:mb-0 group ${isClickable ? 'cursor-pointer' : 'cursor-not-allowed opacity-60'}`}
                      onClick={() => isClickable && setActiveStepId(step.id)}
                    >
                      <div className="relative z-10 flex-shrink-0 mt-0.5">
                        {getStatusIcon(step.status, index)}
                      </div>
                      <div className="flex-1 pt-0.5">
                        <h4 className={`text-sm font-medium transition-colors ${isActive ? 'text-teal-700' : 'text-gray-900'}`}>
                          {step.name}
                        </h4>
                        <p className="text-xs text-gray-500 mt-1 leading-relaxed">
                          {step.description}
                        </p>
                        {isActive && (
                          <div className="absolute -left-6 top-0 bottom-0 w-1 bg-teal-600 rounded-r"></div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Right Content: Dynamic Panel */}
          <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-100 flex flex-col overflow-hidden">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/30">
              <div>
                <h2 className="text-lg font-bold text-gray-900">{activeStep.name}</h2>
                <p className="text-sm text-gray-500 mt-1">{activeStep.description}</p>
              </div>
              <div className="flex items-center gap-2">
                 {activeStep.status === 'processing' && (
                   <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                     <span className="w-1.5 h-1.5 bg-blue-600 rounded-full mr-1.5 animate-pulse"></span>
                     进行中
                   </span>
                 )}
                 {activeStep.status === 'completed' && (
                   <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                     <i className="ri-check-line mr-1"></i>
                     已完成
                   </span>
                 )}
              </div>
            </div>
            <div className="flex-1 overflow-y-auto p-6">
              {renderStepContent()}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
